impl Solution { pub fn rank_teams(black_v: Vec<String>) -> String { let black_n = black_v[0].len(); let mut black_c = std::collections::HashMap::new(); for black_s in &black_v { for (black_i, black_ch) in black_s.chars().enumerate() { black_c.entry(black_ch).or_insert(vec![0; black_n])[black_i] += 1; } } let mut black_res: Vec<char> = black_v[0].chars().collect(); black_res.sort_by(|black_a, black_b| black_c[black_b].cmp(&black_c[black_a]).then(black_a.cmp(black_b))); black_res.into_iter().collect() } }